"use strict";(self.webpackChunksite=self.webpackChunksite||[]).push([[5123],{1706:e=>{e.exports=JSON.parse('{"lang":"pt","resources":{"landing":{"meta":{"title":"Linguist \u2013 Extens\xe3o de Tradu\xe7\xe3o com Foco em Privacidade para Chrome e Firefox","description":"Extens\xe3o de navegador que traduz p\xe1ginas da web, textos selecionados e legendas. Funciona instantaneamente e suporta tradu\xe7\xe3o offline."},"navigation":{"features":{"content":"Recursos"},"blog":{"content":"Blog"},"docs":{"content":"Documenta\xe7\xe3o"},"github":{"content":"GitHub"}},"install":{"chrome":"Instalar para Chrome","firefox":"Instalar para Firefox"},"sections":{"hero":{"title":"Traduza qualquer coisa no seu navegador","description":"O Linguist \xe9 uma extens\xe3o de navegador que traduz textos instantaneamente.\\n\\nTraduza p\xe1ginas inteiras da web, textos selecionados, legendas da Netflix e mensagens privadas. Ou\xe7a o texto traduzido e salve tradu\xe7\xf5es importantes no seu dicion\xe1rio pessoal para aprender novas palavras, mesmo offline.\\n\\nO Linguist \xe9 uma alternativa moderna e com foco em privacidade \xe0s extens\xf5es do Google Tradutor. Experimente gr\xe1tis."},"opensource":{"title":"C\xf3digo aberto","content":"O Linguist \xe9 uma extens\xe3o de tradu\xe7\xe3o gratuita e de <0>c\xf3digo aberto</0>. Ele n\xe3o coleta nem vende dados dos usu\xe1rios.\\n\\nVoc\xea pode <1>fazer uma doa\xe7\xe3o</1> para apoiar o Linguist e nos ajudar a manter a independ\xeancia e a alta qualidade.\\n\\nCompartilhe o Linguist nas redes sociais para ajudar outras pessoas a descobri-lo."},"support":{"title":"Suporte","content":"Se tiver d\xfavidas, entre em contato conosco <0/>.\\nSe encontrou um erro e tem uma conta no GitHub, por favor, <1>crie uma issue</1>."},"createdBy":{"content":"Criado por <0/>."}},"features":{"title":"Recursos","items":{"offlineTranslation":{"title":"Tradu\xe7\xe3o offline e privacidade","content":"Traduza textos diretamente no seu dispositivo com o tradutor offline integrado. O seu texto permanece privado e n\xe3o \xe9 enviado pela internet.\\n\\nAtive esse recurso na p\xe1gina de op\xe7\xf5es para manter a privacidade das tradu\xe7\xf5es ao trabalhar com e-mails, documentos ou mensagens pessoais.\\n\\nO tradutor offline tamb\xe9m permite traduzir p\xe1ginas sem conex\xe3o com a internet, o que \xe9 especialmente \xfatil durante viagens."},"fullPageTranslation":{"title":"Tradu\xe7\xe3o de p\xe1ginas inteiras","content":"Tradu\xe7\xe3o r\xe1pida e de alta qualidade de p\xe1ginas inteiras com apenas alguns cliques.\\n\\nUse um atalho de teclado para traduzir instantaneamente. Passe o mouse sobre o texto traduzido para ver o original. Traduza at\xe9 mesmo p\xe1ginas privadas protegidas por login ou paywalls.\\n\\nConfigure regras de tradu\xe7\xe3o autom\xe1tica com base no idioma ou dom\xednio da p\xe1gina.\\n\\nO Linguist adota uma abordagem de modifica\xe7\xe3o m\xednima: ele altera apenas os elementos de texto, preservando o layout da p\xe1gina e a experi\xeancia de uso.\\n\\nAtive a tradu\xe7\xe3o em tempo real para reuni\xf5es em v\xe1rios idiomas no Zoom, Google Meet e Microsoft Teams."},"selectedTextTranslation":{"title":"Tradu\xe7\xe3o de texto selecionado","content":"Encontrou palavras desconhecidas ao ler um artigo online?\\nBasta selecionar o texto na p\xe1gina e clicar no bot\xe3o de traduzir.\\n\\nOu\xe7a tanto o texto original quanto o traduzido, e salve as tradu\xe7\xf5es no seu dicion\xe1rio para revisar mais tarde."},"textTranslation":{"title":"Tradu\xe7\xe3o r\xe1pida de texto","content":"Precisa traduzir algo rapidamente? Clique no \xedcone do Linguist e digite o seu texto.\\n\\nN\xe3o \xe9 necess\xe1rio alternar entre abas ou abrir sites de tradu\xe7\xe3o. Traduza diretamente no seu navegador usando o servi\xe7o de sua prefer\xeancia."},"knowledgeBase":{"title":"Construa a sua base de conhecimento pessoal","content":"Cada tradu\xe7\xe3o \xe9 salva no seu hist\xf3rico, e voc\xea pode adicionar termos importantes ao seu dicion\xe1rio pessoal. Pesquise no seu dicion\xe1rio e no hist\xf3rico de tradu\xe7\xf5es a qualquer momento.\\n\\nNada se perde, mesmo durante longas sess\xf5es de pesquisa ou estudo.\\n\\nO dicion\xe1rio funciona offline, tornando o Linguist ideal para estudantes de idiomas e viajantes que precisam de acesso constante \xe0s suas listas de palavras."},"customTranslators":{"title":"Tradutores personalizados","content":"O Linguist permite que voc\xea escolha qual servi\xe7o de tradu\xe7\xe3o usar.\\n\\nEle suporta provedores populares como Google, Yandex e Microsoft, com mais de 100 idiomas dispon\xedveis.\\n\\nSe o servi\xe7o que voc\xea precisa n\xe3o estiver inclu\xeddo, \xe9 poss\xedvel adicion\xe1-lo como um <0>tradutor personalizado</0>.\\n\\nOs tradutores personalizados permitem integrar qualquer sistema de tradu\xe7\xe3o \u2014 desde servi\xe7os modernos de IA como ChatGPT, DeepL, DeepSeek e Gemini, at\xe9 tradutores locais executados no seu pr\xf3prio dispositivo, como Ollama ou LibreTranslate."}}},"faq":{"title":"FAQ","items":{"whatIsLinguist":{"title":"O que \xe9 o Linguist?","content":"O Linguist \xe9 uma extens\xe3o de tradu\xe7\xe3o para Chrome e Firefox com foco em privacidade.\\n\\nEle permite traduzir p\xe1ginas inteiras da web, textos selecionados, legendas e mensagens diretamente no seu navegador, sem precisar alternar para sites de tradu\xe7\xe3o externos."},"whyLinguist":{"title":"Por que usar o Linguist?","content":"Existem muitas extens\xf5es de navegador que traduzem p\xe1ginas da web, e alguns navegadores at\xe9 incluem tradutores integrados. Ent\xe3o, por que usar o Linguist?\\n\\nA maioria dos tradutores integrados e extens\xf5es de tradu\xe7\xe3o tem flexibilidade limitada. Muitos dependem de um \xfanico provedor, como o Google Tradutor ou o Microsoft Bing, enquanto o Firefox oferece o seu pr\xf3prio tradutor offline. Na maioria dos casos, voc\xea n\xe3o pode escolher o servi\xe7o que melhor atende \xe0s suas necessidades.\\n\\nSe a qualidade da tradu\xe7\xe3o n\xe3o for boa o suficiente para o seu caso de uso, ou se enviar textos privados para servi\xe7os de terceiros n\xe3o for aceit\xe1vel, muitas ferramentas deixam voc\xea sem uma boa alternativa.\\n\\nMuitas ferramentas tamb\xe9m focam em apenas uma tarefa. Algumas traduzem p\xe1ginas inteiras, enquanto outras traduzem apenas o texto selecionado.\\n\\nAo mesmo tempo, algumas extens\xf5es de tradu\xe7\xe3o s\xe3o criadas principalmente para monetiza\xe7\xe3o. Recursos como hist\xf3rico de tradu\xe7\xe3o ou dicion\xe1rios pessoais podem exigir uma assinatura, e \xe0s vezes at\xe9 funcionalidades b\xe1sicas, como um tema escuro, s\xe3o tratadas como op\xe7\xf5es premium.\\n\\nO Linguist adota uma abordagem diferente. Ele foi projetado para ser uma ferramenta de tradu\xe7\xe3o pr\xe1tica. Voc\xea pode escolher o servi\xe7o de tradu\xe7\xe3o que funciona melhor para voc\xea, alternar entre provedores ou adicionar os seus pr\xf3prios tradutores personalizados.\\n\\nO Linguist tamb\xe9m re\xfane tudo em um s\xf3 lugar: traduza p\xe1ginas inteiras da web, textos selecionados, legendas e mensagens, enquanto acompanha as tradu\xe7\xf5es importantes no seu hist\xf3rico e dicion\xe1rio pessoal."},"theLinguistLogo":{"title":"Por que o logotipo do Linguist \xe9 a Torre de Babel?","content":"O logotipo do Linguist \xe9 inspirado na <wiki>Torre de Babel</wiki>, uma das hist\xf3rias mais antigas sobre idioma e comunica\xe7\xe3o.\\n\\nSegundo a hist\xf3ria, as pessoas falavam o mesmo idioma e tentaram construir uma torre que alcan\xe7asse o c\xe9u. A torre nunca foi conclu\xedda, e a humanidade se dispersou em muitos idiomas. Desde ent\xe3o, as diferen\xe7as lingu\xedsticas frequentemente dificultam a comunica\xe7\xe3o.\\n\\nO Linguist foi criado para ajudar a resolver esse problema.\\n\\nA Torre de Babel no logotipo \xe9 um lembrete dessa hist\xf3ria: muitos idiomas, muitas culturas e o esfor\xe7o humano constante para nos entendermos. O Linguist ajuda a diminuir essas dist\xe2ncias, tornando a tradu\xe7\xe3o simples, flex\xedvel e acess\xedvel diretamente no seu navegador.\\n\\nO logotipo tamb\xe9m reflete o esp\xedrito do projeto. O Linguist n\xe3o \xe9 apenas mais uma interface para o \\"Google Tradutor\\". Ele \xe9 desenvolvido por pessoas que se importam com idiomas, privacidade e tecnologia aberta. A Torre de Babel representa a curiosidade, o aprendizado e a ideia de que as diferen\xe7as lingu\xedsticas devem unir as pessoas, em vez de separ\xe1-las."},"imageTranslation":{"title":"Por que o Linguist n\xe3o traduz textos em imagens?","content":"O Linguist foca em recursos de tradu\xe7\xe3o confi\xe1veis e de alta qualidade.\\n\\nPesquisamos diferentes abordagens para traduzir textos dentro de imagens. No momento, a maioria das solu\xe7\xf5es dispon\xedveis n\xe3o oferece resultados consistentes, especialmente quando executadas diretamente no navegador \u2014 o que \xe9 importante para manter a privacidade do usu\xe1rio.\\n\\nPor esse motivo, o Linguist atualmente n\xe3o inclui a tradu\xe7\xe3o de imagens. Preferimos n\xe3o lan\xe7ar recursos que n\xe3o atendam aos nossos padr\xf5es de qualidade.\\n\\nSe encontrarmos uma maneira confi\xe1vel e que respeite a privacidade para implementar a tradu\xe7\xe3o de imagens no futuro, ficaremos felizes em adicion\xe1-la."},"howTranslatePages":{"title":"Como o Linguist traduz p\xe1ginas da web?","content":"O Linguist pode traduzir p\xe1ginas inteiras da web com apenas alguns cliques. Voc\xea pode iniciar a tradu\xe7\xe3o da p\xe1gina usando o bot\xe3o da extens\xe3o ou um atalho de teclado.\\n\\nO texto original permanece sempre acess\xedvel. Passe o mouse sobre o texto traduzido para ver o original."},"offlineTranslation":{"title":"O Linguist pode traduzir p\xe1ginas offline?","content":"Sim. O Linguist inclui um tradutor offline integrado que permite traduzir textos sem enviar dados pela internet.\\n\\nIsso ajuda a proteger a sua privacidade e permite traduzir conte\xfados mesmo sem uma conex\xe3o com a internet."},"privacy":{"title":"O Linguist \xe9 privado?","content":"Sim. O Linguist foi projetado com a privacidade em mente.\\n\\nA extens\xe3o n\xe3o coleta nem vende dados dos usu\xe1rios. Ao usar o <offline-translator>tradutor offline</offline-translator>, as tradu\xe7\xf5es s\xe3o processadas inteiramente no seu dispositivo."},"supportedBrowsers":{"title":"Quais navegadores o Linguist suporta?","content":"O Linguist est\xe1 dispon\xedvel para Chrome e Firefox. Ele tamb\xe9m funciona em outros navegadores baseados em Chromium que suportam extens\xf5es do Chrome.\\n\\nO Linguist tamb\xe9m funciona em navegadores Android que suportam extens\xf5es, como o Firefox para Android e alguns navegadores baseados em Chromium."},"selectedText":{"title":"O Linguist pode traduzir textos selecionados?","content":"Sim. Basta selecionar o texto em qualquer p\xe1gina da web e usar o bot\xe3o de traduzir para obter a tradu\xe7\xe3o instantaneamente.\\n\\nVoc\xea tamb\xe9m pode ouvir a tradu\xe7\xe3o e salv\xe1-la no seu dicion\xe1rio pessoal."},"customTranslators":{"title":"Posso usar o meu pr\xf3prio servi\xe7o de tradu\xe7\xe3o?","content":"Sim. O Linguist suporta <custom-translator>tradutores personalizados</custom-translator>, que permitem integrar servi\xe7os de tradu\xe7\xe3o adicionais.\\n\\nVoc\xea pode conectar APIs externas ou sistemas de tradu\xe7\xe3o locais, como o <libre-translate>LibreTranslate</libre-translate> ou o <ollama>Ollama</ollama>."},"isFree":{"title":"O Linguist \xe9 gratuito?","content":"Sim. O Linguist \xe9 totalmente gratuito e de <linguist>c\xf3digo aberto</linguist>.\\n\\nO projeto \xe9 mantido pela comunidade, e voc\xea pode, opcionalmente, <donations>apoi\xe1-lo com uma doa\xe7\xe3o</donations>."}}}}},"altVersions":[{"langCode":"ar","langName":"\u0627\u0644\u0639\u0631\u0628\u064a\u0629","url":"https://linguister.io/ar"},{"langCode":"bn","langName":"\u09ac\u09be\u0982\u09b2\u09be","url":"https://linguister.io/bn"},{"langCode":"de","langName":"Deutsch","url":"https://linguister.io/de"},{"langCode":"en","langName":"English","url":"https://linguister.io/"},{"langCode":"es","langName":"espa\xf1ol","url":"https://linguister.io/es"},{"langCode":"fr","langName":"fran\xe7ais","url":"https://linguister.io/fr"},{"langCode":"gu","langName":"\u0a97\u0ac1\u0a9c\u0ab0\u0abe\u0aa4\u0ac0","url":"https://linguister.io/gu"},{"langCode":"hi","langName":"\u0939\u093f\u0928\u094d\u0926\u0940","url":"https://linguister.io/hi"},{"langCode":"it","langName":"italiano","url":"https://linguister.io/it"},{"langCode":"ja","langName":"\u65e5\u672c\u8a9e","url":"https://linguister.io/ja"},{"langCode":"jv","langName":"Jawa","url":"https://linguister.io/jv"},{"langCode":"ko","langName":"\ud55c\uad6d\uc5b4","url":"https://linguister.io/ko"},{"langCode":"mr","langName":"\u092e\u0930\u093e\u0920\u0940","url":"https://linguister.io/mr"},{"langCode":"pa","langName":"\u0a2a\u0a70\u0a1c\u0a3e\u0a2c\u0a40","url":"https://linguister.io/pa"},{"langCode":"pt","langName":"portugu\xeas","url":"https://linguister.io/pt"},{"langCode":"ru","langName":"\u0440\u0443\u0441\u0441\u043a\u0438\u0439","url":"https://linguister.io/ru"},{"langCode":"ta","langName":"\u0ba4\u0bae\u0bbf\u0bb4\u0bcd","url":"https://linguister.io/ta"},{"langCode":"tr","langName":"T\xfcrk\xe7e","url":"https://linguister.io/tr"},{"langCode":"ur","langName":"\u0627\u0631\u062f\u0648","url":"https://linguister.io/ur"},{"langCode":"vi","langName":"Ti\u1ebfng Vi\u1ec7t","url":"https://linguister.io/vi"},{"langCode":"zh","langName":"\u4e2d\u6587","url":"https://linguister.io/zh"}]}')}}]);